const prompt = $input.all()[0]?.json?.output?.prompt;
const imageUrl = $("Upload img to imgBB fro url").all()[0]?.json?.data?.url;

const result = {
  prompt: prompt,
  imageUrls: [imageUrl],
  model: "veo3_fast",
  callBackUrl: "http://your-callback-url.com/complete",
  aspectRatio: "9:16",
  enableFallback: false,
  enableTranslation: false,
};

return [{ json: result }];
